import{_ as e,c as t,o as r,ae as n}from"./chunks/framework.B7Y1jjX-.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/参考文献共4篇（真实论文）.md","filePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/参考文献共4篇（真实论文）.md"}'),a={name:"notes/学习/学校竞赛、项目/数学建模/课程知识/参考文献共4篇（真实论文）.md"};function o(l,i,s,p,g,h){return r(),t("div",null,[...i[0]||(i[0]=[n('<p>==Ke G, Meng Q, Finley T, et al. LightGBM: A highly efficient gradient boosting decision tree[ C ]// <em>Advances in Neural Information Processing Systems 30 (NeurIPS 2017)</em>. 2017.==</p><p>以下是 LightGBM 原论文（NeurIPS 2017）的<strong>中文翻译简介与规范引用</strong>：</p><h2 id="中文翻译简介" tabindex="-1">中文翻译简介 <a class="header-anchor" href="#中文翻译简介" aria-label="Permalink to &quot;中文翻译简介&quot;">​</a></h2><p><strong>论文题目</strong>：<br> LightGBM：一种高效的梯度提升决策树</p><p><strong>作者</strong>：<br> 柯国霖（Guolin Ke）、孟琦（Qi Meng）、Thomas Finley、汪泰峰（Taifeng Wang）、陈炜（Wei Chen）、马伟东（Weidong Ma）、叶启伟（Qiwei Ye）、刘铁岩（Tie-Yan Liu）<br> （微软亚洲研究院、北京大学、微软雷德蒙分部）</p><p><strong>摘要翻译</strong>：<br> 梯度提升决策树（GBDT）是当前最流行的机器学习算法之一，拥有 XGBoost、pGBRT 等多种高效实现。然而在高维特征和大规模数据下，现有实现的效率和可扩展性仍不理想。主要原因是每个特征都需要遍历全部样本来评估所有可能分裂点的信息增益，计算量大。为了解决这一难题，本文提出了两种创新技术：<strong>基于梯度的单边采样（GOSS）</strong> 和 <strong>互斥特征捆绑（EFB）</strong>。</p><ul><li><p>GOSS：优先保留梯度大的样本，仅对梯度小的样本随机采样，从而在显著减少样本量的情况下，依然可以准确估计分裂点的信息增益。</p></li><li><p>EFB：将互斥（极少同时非零）的特征进行捆绑，有效减少特征数，提高计算效率。<br> 理论与实验均表明，LightGBM 能在基本不损失精度的前提下，将训练速度提升 20 倍以上。</p></li></ul><p><strong>论文正文内容</strong>（部分）：</p><ul><li><p>LightGBM 是一种融合 GOSS 和 EFB 的高效 GBDT 算法，显著加速大数据场景下的模型训练；</p></li><li><p>实验在多个公开大规模数据集（如 KDD Cup、LETOR、Allstate）上进行了测试，结果显示 LightGBM 比传统 GBDT、XGBoost 等工具快很多，且精度相当；</p></li><li><p>代码开源：<a href="https://github.com/Microsoft/LightGBM" target="_blank" rel="noreferrer">https://github.com/Microsoft/LightGBM</a></p></li><li><p>适用于高维稀疏特征、高样本量的机器学习、医学判别、风控等领域。</p></li><li><p><strong>中文格式（GB/T 7714）</strong><br> 柯国霖, 孟琦, Thomas Finley, 等. LightGBM: 一种高效的梯度提升决策树[C]// 神经信息处理系统大会（NeurIPS 2017）, 美国加州长滩, 2017.<br> 可下载全文: <a href="https://papers.nips.cc/paper_files/paper/2017/file/6449f44a102fde848669bdd9eb6b76fa-Paper.pdf" target="_blank" rel="noreferrer">https://papers.nips.cc/paper_files/paper/2017/file/6449f44a102fde848669bdd9eb6b76fa-Paper.pdf</a></p></li><li><p><strong>APA 7 格式</strong><br> Ke, G., Meng, Q., Finley, T., Wang, T., Chen, W., Ma, W., Ye, Q., &amp; Liu, T.-Y. (2017). LightGBM: A highly efficient gradient boosting decision tree. In <em>Advances in Neural Information Processing Systems 30 (NeurIPS 2017)</em>. <a href="https://papers.nips.cc/paper_files/paper/2017/file/6449f44a102fde848669bdd9eb6b76fa-Paper.pdf" target="_blank" rel="noreferrer">https://papers.nips.cc/paper_files/paper/2017/file/6449f44a102fde848669bdd9eb6b76fa-Paper.pdf</a></p></li></ul><hr><p>==Ishwaran H, Kogalur U B, Blackstone E H, 等. Random survival forests[J]. The Annals of Applied Statistics, 2008, 2(3): 841–860.==</p><h2 id="中文内容简介-要点分列" tabindex="-1">中文内容简介（要点分列） <a class="header-anchor" href="#中文内容简介-要点分列" aria-label="Permalink to &quot;中文内容简介（要点分列）&quot;">​</a></h2><ul><li><p><strong>研究内容</strong>：<br> 本文提出了一种用于生存数据（即“删失数据”）分析的新型机器学习算法——<strong>随机生存森林</strong>（Random Survival Forests, RSF），它是决策树集成算法（即随机森林）的生存分析扩展。</p></li><li><p><strong>核心思想</strong>：</p><ul><li><p>利用随机森林思想（Bagging + 随机特征选择）对生存（时间到事件、带删失）数据建模。</p></li><li><p>每棵树基于 Bootstrap 重采样样本构建，节点分裂依据“最大化生存差异”（如 log-rank 统计量）。</p></li><li><p>集成大量树，最终输出累计生存概率（或风险函数），对个体的生存时间/达标概率进行非参数估计。</p></li></ul></li><li><p><strong>主要优点</strong>：</p><ul><li><p>能处理高维、多变量、非线性、强交互的数据；</p></li><li><p>对删失（右删失）数据天然支持，无需分布假设；</p></li><li><p>可输出变量重要性、个体生存概率曲线等丰富信息；</p></li><li><p>适合用于医学、生物统计、工业可靠性等领域的“时间到事件”预测。</p></li></ul></li><li><p><strong>应用场景</strong>：</p><ul><li>论文应用于医学（如手术患者存活）、风险预测等多种生存数据分析，实际效果显著优于经典 Cox 比例风险模型等。</li></ul></li></ul><hr><p>好的，以下是<strong>第⑦、⑧篇论文</strong>（分别关于<strong>代价敏感学习</strong>和<strong>选择性预测/拒判</strong>）的<strong>规范引用</strong>和简明中文内容简介：</p><hr><h2 id="第7篇-代价敏感学习-cost-sensitive-learning" tabindex="-1">第⑦篇：代价敏感学习（Cost-Sensitive Learning） <a class="header-anchor" href="#第7篇-代价敏感学习-cost-sensitive-learning" aria-label="Permalink to &quot;第⑦篇：代价敏感学习（Cost-Sensitive Learning）&quot;">​</a></h2><h3 id="规范引用" tabindex="-1">规范引用 <a class="header-anchor" href="#规范引用" aria-label="Permalink to &quot;规范引用&quot;">​</a></h3><p><strong>GB/T 7714 格式</strong><br> ==Elkan C. The foundations of cost-sensitive learning[C]// Proceedings of the 17th International Joint Conference on Artificial Intelligence (IJCAI), Workshop on Cost-Sensitive Learning. 2001: 973-978.==</p><h3 id="中文内容简介" tabindex="-1">中文内容简介 <a class="header-anchor" href="#中文内容简介" aria-label="Permalink to &quot;中文内容简介&quot;">​</a></h3><ul><li><p><strong>研究内容</strong>：<br> 该文是代价敏感学习（Cost-Sensitive Learning）领域的经典基础文献，系统分析了在类别不平衡或不同类型误分类带来不同代价（如漏诊/误诊）情况下的机器学习算法设计问题。</p></li><li><p><strong>核心观点</strong>：</p><ul><li><p>传统机器学习最小化“错误率”，但现实中不同类型错误（如漏诊和误诊）造成的后果（成本）不同。</p></li><li><p>代价敏感学习框架：引入“代价矩阵”或“样本权重”，在训练与预测时动态调整模型，降低高代价错误（如漏诊）。</p></li><li><p>可以通过修改损失函数、调整阈值、重采样等方法实现。</p></li></ul></li><li><p><strong>实际意义</strong>：</p><ul><li><p>医学诊断、金融风控等高风险场景中，往往需要优先降低高代价事件（如“漏诊”）。</p></li><li><p>可与 LightGBM、逻辑回归等方法配合，用于你题目第四问中的“漏诊/误诊权重调节”策略。</p></li></ul></li></ul><hr><h2 id="第8篇-选择性预测-拒判-selective-prediction-classification-with-reject-option" tabindex="-1">第⑧篇：选择性预测/拒判（Selective Prediction/Classification with Reject Option） <a class="header-anchor" href="#第8篇-选择性预测-拒判-selective-prediction-classification-with-reject-option" aria-label="Permalink to &quot;第⑧篇：选择性预测/拒判（Selective Prediction/Classification with Reject Option）&quot;">​</a></h2><h3 id="规范引用-以经典理论为代表" tabindex="-1">规范引用（以经典理论为代表） <a class="header-anchor" href="#规范引用-以经典理论为代表" aria-label="Permalink to &quot;规范引用（以经典理论为代表）&quot;">​</a></h3><p><strong>GB/T 7714 格式</strong><br> ==Chow C K. On optimum recognition error and reject tradeoff[J]. IEEE Transactions on Information Theory, 1970, 16(1): 41–46.==</p><h3 id="中文内容简介-1" tabindex="-1">中文内容简介 <a class="header-anchor" href="#中文内容简介-1" aria-label="Permalink to &quot;中文内容简介&quot;">​</a></h3><ul><li><p><strong>研究内容</strong>：<br> 这是“拒判理论”（选择性预测、带拒绝选项分类）的奠基性论文，首次提出“可拒判分类器”的理论与误差—拒判权衡公式。</p></li><li><p><strong>核心思想</strong>：</p><ul><li><p>对于置信度低的预测样本，模型可以选择“不做判定”而拒绝输出（如临床建议“复检”），以降低整体误差率。</p></li><li><p>数学上，通过设置拒判阈值，在降低错误率和提升拒判率之间取得最优平衡。</p></li></ul></li><li><p><strong>实际应用</strong>：</p><ul><li><p>在医学、金融等高风险领域，用于对“模型不确定”的样本自动触发“建议复检/人工判定”，提升整体安全性。</p></li><li><p>你的题目第四问用到选择性/拒判机制时，可引用该理论基础，说明在低置信度样本上采用拒判能有效降低误判风险。</p></li></ul></li></ul>',27)])])}const f=e(a,[["render",o]]);export{d as __pageData,f as default};
